 * {
  box-sizing: border-box;

}

.row {
  margin-left:-5px;
  margin-right:-5px;
}

.column {
  float: left;
  width: 50%;
  padding: 5px;
}

/* Clearfix (clear floats) */
.row::after {
  content: "";
  clear: both;
  display: table;
}
table{
    padding:-1px;
}


th, td {
  text-align: left;
  padding: 16px;
}
 @page {
       @bottom-left {
            content: counter(page) "https://stackoverflow.com/" counter(pages);
        }
     }
